#include <bits/stdc++.h>
using namespace std;
const int N=1e5+5;
struct Edge{
	int to,val;
};
int n,c[N],siz[N],sum;
long long f[N][2],ans=1e18;
vector<Edge> g[N];
void dfs1(int x,int fa){
	siz[x]=c[x];
	int len=g[x].size();
	for(int i=0;i<len;i++)
		if(g[x][i].to!=fa)
			dfs1(g[x][i].to,x),f[x][0]+=f[g[x][i].to][0]+1LL*siz[g[x][i].to]*g[x][i].val,siz[x]+=siz[g[x][i].to];
}
void dfs2(int x,int fa,int fv){
	if(x==1)
		f[x][1]=f[x][0];
	else
		f[x][1]=f[x][0]+(f[fa][1]-f[x][0]-1LL*siz[x]*fv)+1LL*(sum-siz[x])*fv;
	int len=g[x].size();
	for(int i=0;i<len;i++)
		if(g[x][i].to!=fa)
			dfs2(g[x][i].to,x,g[x][i].val);
	ans=min(ans,f[x][1]);
}
int main(){
	scanf("%d",&n);
	for(int i=1;i<=n;i++){
		scanf("%d",&c[i]);
		sum+=c[i];
	}
	for(int i=1;i<n;i++){
		int a,b,l;
		scanf("%d%d%d",&a,&b,&l);
		g[a].push_back({b,l});
		g[b].push_back({a,l});
	}
	dfs1(1,0);
	dfs2(1,0,0);
	printf("%lld",ans);
	return 0;
}
